import { ZuploContext, ZuploRequest } from "@zuplo/runtime";

export default async function (request: ZuploRequest, context: ZuploContext) {
  return request.user?.data?.plan === "pro";
}

import * as jose from 'jose';

const secret = new TextEncoder().encode('my-super-secret-key');

async function createToken(plan) {
  const jwt = await new jose.SignJWT({ plan })
    .setProtectedHeader({ alg: 'HS256' })
    .setIssuedAt()
    .setExpirationTime('2h')
    .sign(secret);
  return jwt;
}

const freeToken = await createToken('free');
const proToken = await createToken('pro');

console.log('Free Token:', freeToken);
console.log('Pro Token:', proToken);

