import { ZuploContext, ZuploRequest } from "@zuplo/runtime";

export default async function (request: ZuploRequest, context: ZuploContext, options: any, policyName: string) {
  const plan = request.user?.data?.plan;
  if (plan === "pro") {
    return context.invokeInboundPolicy("rate-limit-pro", request);
  } else {
    // Default to free if plan is missing or "free"
    return context.invokeInboundPolicy("rate-limit-free", request);
  }
}
